const triggerInput = $('Webhook Trigger').first().json.body;
const vendor = $('Fetch Vendor Record').first().json;
const config = $('Set: Configuration').first().json;

try {
  const bankChangeWindowDays = parseInt(config.bankChangeWindowDays, 10);
  if (isNaN(bankChangeWindowDays) || bankChangeWindowDays <= 0) {
    throw new Error('Invalid bankChangeWindowDays in config: ' + config.bankChangeWindowDays);
  }

  // QB Vendor.MetaData.LastUpdatedTime is the proxy for bank-detail changes (see assumption A4)
  const lastUpdated = vendor.MetaData?.LastUpdatedTime;

  if (!lastUpdated) {
    return [{
      json: {
        ...triggerInput,
        fraudCheck: {
          status: 'FLAG',
          reason: 'Vendor record missing MetaData.LastUpdatedTime — treating as suspicious by default'
        }
      }
    }];
  }

  const updateTs = new Date(lastUpdated).getTime();
  const nowTs = Date.now();
  if (isNaN(updateTs)) {
    throw new Error('Cannot parse vendor LastUpdatedTime: ' + lastUpdated);
  }

  const daysSinceUpdate = Math.floor((nowTs - updateTs) / (1000 * 60 * 60 * 24));

  if (daysSinceUpdate <= bankChangeWindowDays) {
    return [{
      json: {
        ...triggerInput,
        fraudCheck: {
          status: 'FLAG',
          reason: 'Vendor record was updated ' + daysSinceUpdate + ' days ago (within ' + bankChangeWindowDays + '-day fraud window). Manual confirmation required before posting.',
          lastUpdated: lastUpdated,
          daysSinceUpdate: daysSinceUpdate
        }
      }
    }];
  }

  return [{
    json: {
      ...triggerInput,
      fraudCheck: {
        status: 'PASS',
        lastUpdated: lastUpdated,
        daysSinceUpdate: daysSinceUpdate
      }
    }
  }];

} catch (err) {
  // Fail safe — any error → FLAG. Never silently pass a fraud check.
  return [{
    json: {
      ...triggerInput,
      fraudCheck: {
        status: 'FLAG',
        reason: 'Fraud check error (failed safe): ' + err.message
      }
    }
  }];
}

const triggerInput = $('Webhook Trigger').first().json.body;
// Fetch Live COA returns one item containing { QueryResponse: { Account: [...] } }
const coaList = $('Fetch Live COA').first().json.QueryResponse?.Account ?? [];

try {
  const lineItems = triggerInput.lineItems;
  if (!Array.isArray(lineItems) || lineItems.length === 0) {
    throw new Error('No line items in invoice payload');
  }

  if (!Array.isArray(coaList) || coaList.length === 0) {
    throw new Error('Chart of accounts is empty — Fetch Live COA returned no Account rows');
  }

  // Find AP Control account (assumption A8)
  const apControl = coaList.find(a => a.AccountType === 'Accounts Payable');
  if (!apControl) {
    throw new Error('No Accounts Payable control account found in live COA');
  }

  const journalLines = [];
  const qbBillLines = [];

  for (const li of lineItems) {
    // Match by AcctNum (QB's account code field) OR by Id
    const expenseAccount = coaList.find(a => a.AcctNum === li.expenseAccountCode || a.Id === li.expenseAccountCode);
    if (!expenseAccount) {
      throw new Error('Expense account not found in live COA: ' + li.expenseAccountCode);
    }

    const amount = parseFloat(li.amount);
    if (isNaN(amount) || amount <= 0) {
      throw new Error('Invalid line amount: ' + li.amount);
    }
    const rounded = parseFloat(amount.toFixed(2));

    // Journal-entry shape (for Pre-Posting Gate balance check)
    journalLines.push({
      accountCode: expenseAccount.AcctNum ?? expenseAccount.Id,
      accountId: expenseAccount.Id,
      amount: rounded,
      type: 'debit',
      description: li.description
    });

    // n8n QuickBooks node Bill.Line shape (flat — node wraps into AccountBasedExpenseLineDetail internally)
    qbBillLines.push({
      Amount: rounded,
      DetailType: 'AccountBasedExpenseLineDetail',
      Description: li.description,
      accountId: expenseAccount.Id
    });
  }

  // Sum of debits — must equal totalAmount to 2dp (gate would catch this, but fail fast here for clarity)
  const sumDebits = parseFloat(journalLines.reduce((s, l) => s + l.amount, 0).toFixed(2));
  const totalAmount = parseFloat(parseFloat(triggerInput.totalAmount).toFixed(2));
  if (sumDebits !== totalAmount) {
    throw new Error('Line items (' + sumDebits.toFixed(2) + ') do not sum to invoice total (' + totalAmount.toFixed(2) + ')');
  }

  // Add the AP Control credit line (for the gate's balance check; QB itself auto-handles AP credit)
  journalLines.push({
    accountCode: apControl.AcctNum ?? apControl.Id,
    accountId: apControl.Id,
    amount: totalAmount,
    type: 'credit',
    description: 'AP Control credit for invoice ' + triggerInput.invoiceNumber + ' | vendor ' + triggerInput.vendorId
  });

  return [{
    json: {
      ...triggerInput,
      journalEntry: {
        lines: journalLines,
        totalAmount: totalAmount,
        currency: triggerInput.currency,
        periodDate: triggerInput.invoiceDate
      },
      qbBillLines: qbBillLines,
      apControlAccount: {
        code: apControl.AcctNum,
        id: apControl.Id,
        name: apControl.Name
      }
    }
  }];

} catch (err) {
  // Build failure cannot continue — throw to route to Error Workflow
  throw new Error('Build journal entry failed: ' + err.message);
}

function sha256_8(str) {
  let h1 = 0xdeadbeef, h2 = 0x41c6ce57;
  for (let i = 0, ch; i < str.length; i++) {
    ch = str.charCodeAt(i);
    h1 = Math.imul(h1 ^ ch, 2654435761);
    h2 = Math.imul(h2 ^ ch, 1597334677);
  }
  h1 = Math.imul(h1 ^ (h1 >>> 16), 2246822507) ^ Math.imul(h2 ^ (h2 >>> 13), 3266489909);
  h2 = Math.imul(h2 ^ (h2 >>> 16), 2246822507) ^ Math.imul(h1 ^ (h1 >>> 13), 3266489909);
  const hash = 4294967296 * (2097151 & h2) + (h1 >>> 0);
  return hash.toString(16).padStart(14, '0').slice(0, 8);
}

function redactValue(key, value) {
  if (value === null || value === undefined) return value;
  if (typeof value !== 'string') return value;

  if (/(^|[._-])(vendor|payee|contact|display|company)[._-]?name$/i.test(key) || key === 'DisplayName' || key === 'CompanyName') {
    return 'V_' + sha256_8(value);
  }

  if (/(bank|account|iban|sort|routing).*?(number|code|account)/i.test(key) || key === 'BankAccountNumber' || key === 'IBAN') {
    const cleaned = value.replace(/\s|-/g, '');
    return cleaned.length > 4 ? '****' + cleaned.slice(-4) : '****';
  }

  if (/email/i.test(key)) {
    const at = value.indexOf('@');
    if (at <= 0) return 'E_invalid';
    return 'E_' + sha256_8(value.slice(0, at)) + value.slice(at);
  }

  return value;
}

function deepRedact(input) {
  if (input === null || input === undefined) return input;
  if (Array.isArray(input)) return input.map(deepRedact);
  if (typeof input !== 'object') return input;

  const result = {};
  for (const [key, value] of Object.entries(input)) {
    if (typeof value === 'object' && value !== null) {
      result[key] = deepRedact(value);
    } else {
      result[key] = redactValue(key, value);
    }
  }
  return result;
}

const item = $input.first().json;

try {
  const redactedPayload = deepRedact(item);
  const redactedVendorId = item.body?.vendorId
    ? 'V_' + sha256_8(item.body.vendorId)
    : (item.vendorId ? 'V_' + sha256_8(item.vendorId) : null);

  const qbResponse = (() => { try { return $('QuickBooks: Create Bill')?.first?.()?.json ?? null; } catch(e) { return null; } })();
  const redactedQbResponse = qbResponse ? deepRedact(qbResponse) : null;

  return [{
    json: {
      ...item,
      _piiRedacted: true,
      _piiRedactedAt: new Date().toISOString(),
      redactedVendorId: redactedVendorId,
      redactedPayload: redactedPayload,
      redactedQbResponse: redactedQbResponse
    }
  }];

} catch (err) {
  throw new Error('PII redaction failed (refusing to proceed): ' + err.message);
}

const item = $input.first().json;
const triggerInput = $('Webhook Trigger').first().json.body;
const config = $('Set: Configuration').first().json;

try {
  const totalAmount = parseFloat(triggerInput.totalAmount);
  const materialityThreshold = parseFloat(config.materialityThreshold);
  const approvedTemplates = Array.isArray(config.approvedTemplates) ? config.approvedTemplates : [];
  const accountScope = Array.isArray(config.accountScope) ? config.accountScope : [];

  if (isNaN(totalAmount) || isNaN(materialityThreshold)) {
    throw new Error('Invalid amount or threshold: total=' + triggerInput.totalAmount + ', threshold=' + config.materialityThreshold);
  }

  const reasons = [];

  // Control 1: monetary threshold
  if (totalAmount >= materialityThreshold) {
    reasons.push('amount_above_threshold:' + totalAmount.toFixed(2) + '>=' + materialityThreshold.toFixed(2));
  }

  // Control 2: entry-type whitelist (assumption A7 — defaults to ad_hoc)
  const entryType = triggerInput.entryType ?? 'ad_hoc';
  if (!approvedTemplates.includes(entryType)) {
    reasons.push('entry_type_not_pre_approved:' + entryType);
  }

  // Control 3: account scope. Pull journal lines from upstream (carried via Build Journal Entry through PII Redact through audit log node — re-source from Build Journal Entry to be safe)
  const journalLines = $('Build Journal Entry').item.json.journalEntry?.lines ?? [];
  const lineAccounts = journalLines.filter(l => l.type === 'debit').map(l => l.accountCode);
  const outOfScope = lineAccounts.filter(c => !accountScope.includes(c));
  if (outOfScope.length > 0) {
    reasons.push('accounts_out_of_scope:' + outOfScope.join(','));
  }

  // Accounting-domain red flag (assumption A6): round-number invoice, no attachment
  const isRoundThousand = totalAmount > 0 && totalAmount % 1000 === 0;
  const hasAttachment = !!triggerInput.attachmentUrl && triggerInput.attachmentUrl.length > 0;
  if (isRoundThousand && !hasAttachment) {
    reasons.push('round_number_no_attachment:' + totalAmount.toFixed(2));
  }

  const decision = reasons.length === 0 ? 'AUTO_POST' : 'REQUIRES_APPROVAL';

  return [{
    json: {
      ...item,
      materialityClassification: decision,
      routingReasons: reasons,
      _materialityChecked: true
    }
  }];

} catch (err) {
  // Fail safe: any router error → REQUIRES_APPROVAL (manual review).
  return [{
    json: {
      ...item,
      materialityClassification: 'REQUIRES_APPROVAL',
      routingReasons: ['router_error:' + err.message],
      _materialityChecked: true,
      _routerErrored: true
    }
  }];
}
